import React, { useState } from 'react';
import { useStripe, useElements, CardElement } from '@stripe/react-stripe-js';
import './payment.css'; // Your custom CSS

const API_BASE_URL = 'https://e-nutritionist-08e05a1c6652.herokuapp.com'; // Update with your actual backend URL
const API_Local_Host = "http://localhost:3000";


const CheckoutForm = ({ bookingId, amount, onPaymentSuccess }) => {
  const url = API_BASE_URL;

  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();

    if (!stripe || !elements) {
      return;
    }

    setLoading(true);
    setError(null);

    const cardElement = elements.getElement(CardElement);

    try {
      const paymentIntentResponse = await fetch(`${url}/payments/create_payment_intent`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          booking_id: bookingId,
          amount: amount, // In cents
        }),
      });

      if (!paymentIntentResponse.ok) {
        throw new Error('Failed to create Payment Intent');
      }

      const { clientSecret } = await paymentIntentResponse.json();

      const { paymentIntent, error: stripeError } = await stripe.confirmCardPayment(clientSecret, {
        payment_method: {
          card: cardElement,
        },
      });

      if (stripeError) {
        setError(`Payment failed: ${stripeError.message}`);
        setLoading(false);
        return;
      }

      if (paymentIntent.status === 'succeeded') {
        onPaymentSuccess(paymentIntent);
      } else {
        setError('Payment processing error, please try again.');
      }
    } catch (error) {
      setError(`Payment failed: ${error.message}`);
    }

    setLoading(false);
  };

  return (
    <div className="payment-container">
      <div className="payment-card">
        <form className="payment-form" onSubmit={handleSubmit}>
          <h2 className="payment-title">Complete Your Payment</h2>

          <div className="card-details">
            <label htmlFor="card-element" className="card-label">Card Details</label>
            <div className="stripe-card-input">
              <CardElement className="card-element" />
            </div>
          </div>

          <button type="submit" className="payment-button" disabled={!stripe || loading}>
            {loading ? 'Processing...' : `Pay €${(amount / 100).toFixed(2)}`}
          </button>

          {error && <div className="error-message">{error}</div>}
        </form>
      </div>
    </div>
  );
};

export default CheckoutForm;
